package src.org.apache.lucene.index;

final private static class CommitPoint extends IndexCommit implements Comparable { long gen ; List files ; String segmentsFileName ; boolean deleted ; Directory directory ; Collection commitsToDelete ; long version ; long generation ; final boolean isOptimized ; public CommitPoint ( Collection commitsToDelete , Directory directory , SegmentInfos segmentInfos ) throws IOException { this . directory = directory ; this . commitsToDelete = commitsToDelete ; segmentsFileName = segmentInfos . getCurrentSegmentFileName ( ) ; version = segmentInfos . getVersion ( ) ; generation = segmentInfos . getGeneration ( ) ; int size = segmentInfos . size ( ) ; files = new ArrayList ( size ) ; files . add ( segmentsFileName ) ; gen = segmentInfos . getGeneration ( ) ; for ( int i = 0 ; i < size ; i ++ ) { SegmentInfo segmentInfo = segmentInfos . info ( i ) ; if ( segmentInfo . dir == directory ) { files . addAll ( segmentInfo . files ( ) ) ; } } isOptimized = segmentInfos . size ( ) == 1 && ! segmentInfos . info ( 0 ) . hasDeletions ( ) ; } public boolean isOptimized ( ) { return isOptimized ; } public String getSegmentsFileName ( ) { return segmentsFileName ; } public Collection getFileNames ( ) throws IOException { return Collections . unmodifiableCollection ( files ) ; } public Directory getDirectory ( ) { return directory ; } public long getVersion ( ) { return version ; } public long getGeneration ( ) { return generation ; } public void delete ( ) { if ( ! deleted ) { deleted = true ; commitsToDelete . add ( this ) ; } } public boolean isDeleted ( ) { return deleted ; } public int compareTo ( Object obj ) { CommitPoint commit = ( CommitPoint ) obj ; if ( gen < commit . gen ) { return - 1 ; } else if ( gen > commit . gen ) { return 1 ; } else { return 0 ; } } }